from functools import lru_cache
import sys
sys.setrecursionlimit(1000000)

FILES = "abcdefgh"

def kmoves(f, r):
    for df in (-1, 0, 1):
        for dr in (-1, 0, 1):
            if df == 0 and dr == 0:
                continue
            nf, nr = f + df, r + dr
            if 0 <= nf < 8 and 1 <= nr <= 8:
                yield (nf, nr)

def kings_touch(a, b):
    return max(abs(a[0] - b[0]), abs(a[1] - b[1])) <= 1

@lru_cache(maxsize=None)
def result(wk, bk, pf, pr, side):
    # White: single pawn marching up (increasing rank). 'W' = White promotes/wins, 'D' = draw.
    if pr == 8:
        return 'W'
    if (pf, pr) == bk:
        return 'D'  # pawn captured -> KvK draw
    if side == 'w':
        for nk in kmoves(*wk):
            if nk == (pf, pr):
                continue
            if kings_touch(nk, bk):
                continue
            if result(nk, bk, pf, pr, 'b') == 'W':
                return 'W'
        if (pf, pr) != wk:
            if (pf, pr + 1) != wk and (pf, pr + 1) != bk:
                if result(wk, bk, pf, pr + 1, 'b') == 'W':
                    return 'W'
            if pr == 2:
                if (pf, 3) != wk and (pf, 3) != bk and (pf, 4) != wk and (pf, 4) != bk:
                    if result(wk, bk, pf, 4, 'b') == 'W':
                        return 'W'
        return 'D'
    else:
        moved = False
        for nk in kmoves(*bk):
            if kings_touch(wk, nk):
                continue
            moved = True
            if result(wk, nk, pf, pr, 'w') == 'D':
                return 'D'
        if not moved:
            return 'D'  # stalemate
        return 'W'

def P(s):
    return (FILES.index(s[0]), int(s[1]))

def res(wk, bk, p, side):
    pf, pr = P(p)
    return result(P(wk), P(bk), pf, pr, side)

