def trace(start):
    s=start; line=[]
    for _ in range(60):
        wk,bk,p,side=s; pf,pr=p
        if val[s]!='W':
            line.append("[draw reached]"); break
        if side=='w':
            best=None;bd=10**9
            for nk in kmoves(*wk):
                if nk==p or touch(nk,bk): continue
                ns=(nk,bk,p,'b')
                if val[ns]=='W' and dist[ns]<bd: bd=dist[ns]; best=('K',ns,'K'+sqn(nk))
            if p!=wk:
                np1=(pf,pr+1)
                if np1!=wk and np1!=bk:
                    if pr+1==8:
                        if 1<bd: bd=1; best=('P8',None,FILES[pf]+'8=Q')
                    elif val[(wk,bk,np1,'b')]=='W' and 1+dist[(wk,bk,np1,'b')]<bd:
                        bd=1+dist[(wk,bk,np1,'b')]; best=('P',(wk,bk,np1,'b'),FILES[pf]+str(pr+1))
            line.append(best[2])
            if best[0]=='P8': line.append("(promotes, wins)"); break
            s=best[1]
        else:
            best=None;bd=-1
            for nk in kmoves(*bk):
                if touch(wk,nk) or nk==p: continue
                ns=(wk,nk,p,'w')
                if dist[ns]>bd: bd=dist[ns]; best=(ns,'K'+sqn(nk))
            if best is None: line.append("(stalemate/draw)"); break
            line.append(best[1]); s=best[0]
    return line

